module current_sensor (
    input [9:0] voltage_below_threshold,
    input [9:0] threshold,
    output reg current_exceeds
);

always @(*) begin
    if (voltage_below_threshold > threshold) begin
        current_exceeds = 1'b1;
    end else begin
        current_exceeds = 1'b0;
    end
end

endmodule
